{"code":"import json

with open(locals()['var_function-call-11210037646110464087'], 'r') as f:
    cases = json.load(f)

order_items = locals()['var_function-call-14265894602409130757']
target_oi_ids = set()
for oi in order_items:
    target_oi_ids.add(oi['Id'].strip().lstrip('#'))

target_dates = ["2022-09-16", "2022-10-01"]
matched_issues = []

for case in cases:
    # Check if date matches (starts with)
    matches_date = False
    for td in target_dates:
        if case['createddate'].startswith(td):
            matches_date = True
            break

    if matches_date:
        c_oi = case['orderitemid__c']
        if c_oi and c_oi.strip().lstrip('#') in target_oi_ids:
            matched_issues.append(case['issueid__c'])

print("__RESULT__:")
print(json.dumps(matched_issues))"}

